1	import { defineChannelPluginEntry } from "openclaw/plugin-sdk/core";
2	import { nostrPlugin } from "./src/channel.js";
3	import type { NostrProfile } from "./src/config-schema.js";
4	import { createNostrProfileHttpHandler } from "./src/nostr-profile-http.js";
5	import { getNostrRuntime, setNostrRuntime } from "./src/runtime.js";
6	import { resolveNostrAccount } from "./src/types.js";
7	
8	export { nostrPlugin } from "./src/channel.js";
9	export { setNostrRuntime } from "./src/runtime.js";
10	
11	export default defineChannelPluginEntry({
12	  id: "nostr",
13	  name: "Nostr",
14	  description: "Nostr DM channel plugin via NIP-04",
15	  plugin: nostrPlugin,
16	  setRuntime: setNostrRuntime,
17	  registerFull(api) {
18	    const httpHandler = createNostrProfileHttpHandler({
19	      getConfigProfile: (accountId: string) => {
20	        const runtime = getNostrRuntime();
21	        const cfg = runtime.config.loadConfig();
22	        const account = resolveNostrAccount({ cfg, accountId });
23	        return account.profile;
24	      },
25	      updateConfigProfile: async (accountId: string, profile: NostrProfile) => {
26	        const runtime = getNostrRuntime();
27	        const cfg = runtime.config.loadConfig();
28	
29	        const channels = (cfg.channels ?? {}) as Record<string, unknown>;
30	        const nostrConfig = (channels.nostr ?? {}) as Record<string, unknown>;
31	
32	        await runtime.config.writeConfigFile({
33	          ...cfg,
34	          channels: {
35	            ...channels,
36	            nostr: {
37	              ...nostrConfig,
38	              profile,
39	            },
40	          },
41	        });
42	      },
43	      getAccountInfo: (accountId: string) => {
44	        const runtime = getNostrRuntime();
45	        const cfg = runtime.config.loadConfig();
46	        const account = resolveNostrAccount({ cfg, accountId });
47	        if (!account.configured || !account.publicKey) {
48	          return null;
49	        }
50	        return {
51	          pubkey: account.publicKey,
52	          relays: account.relays,
53	        };
54	      },
55	      log: api.logger,
56	    });
57	
58	    api.registerHttpRoute({
59	      path: "/api/channels/nostr",
60	      auth: "gateway",
61	      match: "prefix",
62	      handler: httpHandler,
63	    });
64	  },
65	});
