75	async function resolveNostrDirectAccess(params: {
76	  cfg: Parameters<typeof resolveInboundDirectDmAccessWithRuntime>[0]["cfg"];
77	  accountId: string;
78	  dmPolicy: "pairing" | "allowlist" | "open" | "disabled";
