83	}) {
84	  return resolveInboundDirectDmAccessWithRuntime({
85	    cfg: params.cfg,
86	    channel: "nostr",
87	    accountId: params.accountId,
88	    dmPolicy: params.dmPolicy,
89	    allowFrom: params.allowFrom,
90	    senderId: params.senderPubkey,
91	    rawBody: params.rawBody,
92	    isSenderAllowed: isNostrSenderAllowed,
93	    runtime: params.runtime,
94	    modeWhenAccessGroupsOff: "configured",
95	  });
96	}
