```typescript
export const nostrPlugin: ChannelPlugin<ResolvedNostrAccount> = createChatChannelPlugin({
  base: {
    id: "nostr",
    meta: {
      id: "nostr",
      label: "Nostr",
      selectionLabel: "Nostr",
      docsPath: "/channels/nostr",
      docsLabel: "nostr",
      blurb: "Decentralized DMs via Nostr relays (NIP-04)",
      order: 100,
    },
    capabilities: {
      chatTypes: ["direct"], // DMs only for MVP
      media: false, // No media for MVP
    },
    reload: { configPrefixes: ["channels.nostr"] },
    configSchema: buildChannelConfigSchema(NostrConfigSchema),
    setup: nostrSetupAdapter,
    setupWizard: nostrSetupWizard,
    config: {
      ...nostrConfigAdapter,
      isConfigured: (account) => account.configured,
      describeAccount: (account) =>
        describeAccountSnapshot({
          account,
          configured: account.configured,
          extra: {
            publicKey: account.publicKey,
          },
        }),
    },
    messaging: {
      normalizeTarget: (target) => {
        const cleaned = target.trim().replace(/^nostr:/i, "");
        try {
          return normalizePubkey(cleaned);
        } catch {
          return cleaned;
        }
      },
      targetResolver: {
        looksLikeId: (input) => {
          const trimmed = input.trim();
          return trimmed.startsWith("npub1") || /^[0-9a-fA-F]{64}$/.test(trimmed);
        },
        hint: "<npub|hex pubkey|nostr:npub...>",
      },
      resolveOutboundSessionRoute: (params) => resolveNostrOutboundSessionRoute(params),
    },
    status: {
      ...createComputedAccountStatusAdapter<ResolvedNostrAccount>({
        defaultRuntime: createDefaultChannelRuntimeState(DEFAULT_ACCOUNT_ID),
        collectStatusIssues: (accounts) => collectStatusIssuesFromLastError("nostr", accounts),
        buildChannelSummary: ({ snapshot }) =>
          buildPassiveChannelStatusSummary(snapshot, {
            publicKey: snapshot.publicKey ?? null,
          }),
        resolveAccountSnapshot: ({ account, runtime }) => ({
          accountId: account.accountId,
          name: account.name,
          enabled: account.enabled,
          configured: account.configured,
          extra: {
            publicKey: account.publicKey,
            profile: account.profile,
            ...buildTrafficStatusSummary(runtime),
          },
        }),
      }),
    },
    gateway: {
      startAccount: async (ctx) => {
        // ... extensive setup with bus handles, pairing, inbound/outbound routing
        // ... metrics, error handling, lifecycle
        return {
          stop: () => {
            bus.close();
            activeBuses.delete(account.accountId);
            metricsSnapshots.delete(account.accountId);
          },
        };
      },
    },
  },
  pairing: {
    text: {
      idLabel: "nostrPubkey",
      message: "Your pairing request has been approved!",
      normalizeAllowEntry: (entry) => {
        try {
          return normalizePubkey(entry.trim().replace(/^nostr:/i, ""));
        } catch {
          return entry.trim();
        }
      },
      notify: async ({ id, message }) => {
        const bus = activeBuses.get(DEFAULT_ACCOUNT_ID);
        if (bus) {
          await bus.sendDm(id, message);
        }
      },
    },
  },
  security: {
    resolveDmPolicy: resolveNostrDmPolicy,
  },
  outbound: {
    deliveryMode: "direct",
    textChunkLimit: 4000,
    sendText: async ({ cfg, to, text, accountId }) => {
      const core = getNostrRuntime();
      const aid = accountId ?? DEFAULT_ACCOUNT_ID;
      const bus = activeBuses.get(aid);
      if (!bus) {
        throw new Error(`Nostr bus not running for account ${aid}`);
      }
      const tableMode = core.channel.text.resolveMarkdownTableMode({
        cfg,
        channel: "nostr",
        accountId: aid,
      });
      const message = core.channel.text.convertMarkdownTables(text ?? "", tableMode);
      const normalizedTo = normalizePubkey(to);
      await bus.sendDm(normalizedTo, message);
      return attachChannelToResult("nostr", {
        to: normalizedTo,
        messageId: `nostr-${Date.now()}`,
      });
    },
  },
});
```

Key patterns:
- **Inline meta**: Does NOT use `getChatChannelMeta("nostr")` — just builds it directly
- **Shorthand outbound**: Uses single `outbound` object with `deliveryMode`, `textChunkLimit`, `sendText` directly
- **Config adapter composition**: `nostrConfigAdapter` created inline using `createTopLevelChannelConfigAdapter`
- **Direct imports from runtime-api**: Uses `DEFAULT_ACCOUNT_ID`, `buildChannelConfigSchema`, helper functions
- **Account state management**: Maps for `activeBuses` and `metricsSnapshots` stored at module level
- **Pairing/security**: Simplified compared to IRC; uses `createScopedDmSecurityResolver`
- **Messaging normalization**: Handles pub key format conversion with `normalizePubkey` and prefix stripping

