import { createTopLevelChannelConfigAdapter } from "openclaw/plugin-sdk/channel-config-helpers";
import { attachChannelToResult } from "openclaw/plugin-sdk/channel-send-result";
import { createChatChannelPlugin } from "openclaw/plugin-sdk/core";
import type { ChannelPlugin } from "openclaw/plugin-sdk/core";
import type { PulseBoardAccount } from "./types.js";

// Minimal config adapter with stub account resolution.
// Full resolution would read from cfg.channels.pulseboard.
const pulseBoardConfigAdapter = createTopLevelChannelConfigAdapter<PulseBoardAccount>({
  sectionKey: "pulseboard",
  resolveAccount: (_cfg) => ({
    boardUrl: "",
    apiToken: "",
    username: "",
  }),
  listAccountIds: (_cfg) => [],
  defaultAccountId: (_cfg) => "default",
  deleteMode: "clear-fields",
  clearBaseFields: ["boardUrl", "apiToken", "username"],
  resolveAllowFrom: (_account) => undefined,
  formatAllowFrom: (allowFrom) => allowFrom.map(String).filter(Boolean),
});

export const pulseBoardPlugin: ChannelPlugin<PulseBoardAccount> = createChatChannelPlugin({
  base: {
    id: "pulseboard",
    meta: {
      id: "pulseboard",
      label: "PulseBoard",
      selectionLabel: "PulseBoard",
      docsPath: "/channels/pulseboard",
      blurb: "Real-time bulletin board messaging via named boards and direct messages.",
    },
    capabilities: {
      chatTypes: ["direct", "group"],
      media: false,
    },
    reload: { configPrefixes: ["channels.pulseboard"] },
    config: {
      ...pulseBoardConfigAdapter,
      isConfigured: (account) =>
        account.boardUrl.length > 0 && account.apiToken.length > 0,
    },
    // Stub setup adapter — writes nothing; a real implementation would
    // persist boardUrl/apiToken/username into the config file.
    setup: {
      applyAccountConfig: ({ cfg }) => cfg,
    },
    // Stub gateway adapter — logs the connection attempt; a real
    // implementation would open a WebSocket to the PulseBoard server.
    gateway: {
      startAccount: async (ctx) => {
        ctx.log?.info(
          `[pulseboard] connecting account "${ctx.account.username}" to ${ctx.account.boardUrl}`,
        );
        return {
          stop: () => {},
        };
      },
    },
    messaging: {
      normalizeTarget: (target) => target.trim(),
    },
  },
  outbound: {
    deliveryMode: "direct",
    textChunkLimit: 4000,
    sendText: async ({ to, accountId }) => {
      // Stub delivery — a real implementation would POST to the PulseBoard API.
      const aid = accountId ?? "default";
      return attachChannelToResult("pulseboard", {
        to,
        messageId: `pb-${aid}-${Date.now()}`,
      });
    },
  },
});

